1483:
SELECT SUM(Consumption) AS TotalConsumption
FROM yearmonth
WHERE CustomerID = 6 AND Date BETWEEN '201308' AND '201311';

567:
SELECT COUNT(*) AS NumberOfPosts
FROM posts
WHERE OwnerUserId = (SELECT Id FROM users WHERE DisplayName = 'Tiago Pasqualini');

687:
SELECT COUNT(*) AS NumberOfComments
FROM comments
WHERE PostId = (SELECT Id FROM posts ORDER BY Score DESC LIMIT 1);

