SELECT CAST(COUNT(CASE WHEN bond_type = '=' THEN 1 ELSE NULL END) AS REAL) * 100 / COUNT(*) AS "percent"
FROM bond
WHERE molecule_id = 'TR008';

228:
SELECT CAST(COUNT(CASE WHEN element = 'h' THEN 1 ELSE NULL END) AS REAL) * 100 / COUNT(atom_id) AS percent
FROM atom
WHERE molecule_id = 'TR206';
